#include <stdio.h>
#include <sys/wait.h>
void decode_status(int status) {
    if (WIFEXITED(status)) {
        printf("Sortie normale, code=%d\n", WEXITSTATUS(status));
    } else if (WIFSIGNALED(status)) {
        printf("Tue par signal %d\n", WTERMSIG(status));
    } else {
        printf("Status inconnu: %d\n", status);
    }
}
int main(void) {
    decode_status(0);
    decode_status(256);
    decode_status(512);
    decode_status(9);
    decode_status(2);
    return 0;
}

