#include <stdio.h>
#include <sys/wait.h>

// ★ Stage 0 — Exemple complet
void decode_status(int status) {
    if (WIFEXITED(status)) {              // ★ (status & 0x7f) == 0
        printf("Sortie normale, code=%d\n", WEXITSTATUS(status)); // ★ (status >> 8) & 0xff
    } else if (WIFSIGNALED(status)) {     // ★ low 7 bits non nuls
        printf("Tue par signal %d\n", WTERMSIG(status)); // ★ status & 0x7f
    } else {
        printf("Status inconnu: %d\n", status);
    }
}

int main(void) {
    decode_status(0);   // exit(0)
    decode_status(256); // exit(1)
    decode_status(512); // exit(2)
    decode_status(9);   // signal 9 (SIGKILL)
    decode_status(2);   // signal 2 (SIGINT)
    return 0;
}

